1	import { useState } from "react";
2	import { useSession } from "@/features/session/context";
3	import { useProbabilityEdit } from "@/lib/query/hooks";
4	import { formatProbability } from "@/lib/utils/format";
5	import type { Market } from "@/lib/api/types";
6	
7	interface TradingPanelProps {
8	  market: Market;
9	}
10	
11	export function TradingPanel({ market }: TradingPanelProps) {
12	  const { session, isConfigured } = useSession();
13	  const mutation = useProbabilityEdit(market.id);
14	
15	  const [outcomeId, setOutcomeId] = useState(market.outcomes[0]?.id ?? "");
16	  const [probability, setProbability] = useState(0.5);
17	
18	  if (!isConfigured) {
19	    return (
20	      <div style={{
21	        padding: "var(--space-md)",
22	        borderRadius: "var(--radius-md)",
23	        border: "1px solid var(--color-border)",
24	        background: "var(--color-bg-surface)",
25	        color: "var(--color-text-muted)",
26	        textAlign: "center",
27	      }}>
28	        Set your Account ID in the header to trade.
29	      </div>
30	    );
31	  }
32	
33	  const handleSubmit = (e: React.FormEvent) => {
34	    e.preventDefault();
35	    mutation.mutate({
36	      payload: {
37	        accountId: session.accountId,
38	        variableId: market.variableId,
39	        target: { kind: "marginal", outcomeId, probability },
40	        context: [],
41	        idempotencyKey: crypto.randomUUID(),
42	      },
43	      session,
44	    });
45	  };
46	
47	  return (
48	    <div style={{
49	      padding: "var(--space-md)",
50	      borderRadius: "var(--radius-md)",
51	      border: "1px solid var(--color-border)",
52	      background: "var(--color-bg-surface)",
53	    }}>
54	      <h3 style={{ fontSize: "1rem", fontWeight: 600, marginBottom: "var(--space-md)" }}>Probability Edit</h3>
55	      <form onSubmit={handleSubmit} style={{ display: "grid", gap: "var(--space-md)" }}>
56	        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "var(--space-md)" }}>
57	          <label style={{ fontSize: "0.85rem" }}>
58	            <span style={{ display: "block", color: "var(--color-text-muted)", marginBottom: "var(--space-xs)" }}>Outcome</span>
59	            <select
60	              value={outcomeId}
61	              onChange={(e) => setOutcomeId(e.target.value)}
62	              style={inputStyle}
63	            >
64	              {market.outcomes.map((o) => (
65	                <option key={o.id} value={o.id}>
66	                  {o.name} ({formatProbability(market.marginals[o.id] ?? 0)})
67	                </option>
68	              ))}
69	            </select>
70	          </label>
71	          <label style={{ fontSize: "0.85rem" }}>
72	            <span style={{ display: "block", color: "var(--color-text-muted)", marginBottom: "var(--space-xs)" }}>
73	              New Probability: {formatProbability(probability)}
74	            </span>
75	            <input
76	              type="range"
77	              min={0.01}
78	              max={0.99}
79	              step={0.01}
80	              value={probability}
81	              onChange={(e) => setProbability(Number(e.target.value))}
82	              style={{ width: "100%" }}
83	            />
84	          </label>
85	        </div>
86	        <button
87	          type="submit"
88	          disabled={mutation.isPending}
89	          style={{
90	            padding: "8px 16px",
91	            borderRadius: "var(--radius-sm)",
92	            border: "none",
93	            background: "var(--color-primary)",
94	            color: "#fff",
95	            fontWeight: 600,
96	            cursor: mutation.isPending ? "not-allowed" : "pointer",
97	            opacity: mutation.isPending ? 0.6 : 1,
98	          }}
99	        >
100	          {mutation.isPending ? "Submitting…" : "Submit Edit"}
101	        </button>
102	      </form>
103	
104	      {mutation.isSuccess && (
105	        <div style={{
106	          marginTop: "var(--space-md)",
107	          padding: "var(--space-sm) var(--space-md)",
108	          borderRadius: "var(--radius-sm)",
109	          background: "rgba(34, 197, 94, 0.1)",
110	          border: "1px solid var(--color-success)",
111	          fontSize: "0.85rem",
112	        }}>
113	          Order accepted: {mutation.data.order.orderId}
114	        </div>
115	      )}
116	
117	      {mutation.isError && (
118	        <div style={{
119	          marginTop: "var(--space-md)",
120	          padding: "var(--space-sm) var(--space-md)",
121	          borderRadius: "var(--radius-sm)",
122	          background: "rgba(239, 68, 68, 0.1)",
123	          border: "1px solid var(--color-danger)",
124	          fontSize: "0.85rem",
125	          color: "var(--color-danger)",
126	        }}>
127	          {mutation.error instanceof Error ? mutation.error.message : "Trade failed"}
128	        </div>
129	      )}
130	    </div>
131	  );
132	}
133	
134	const inputStyle: React.CSSProperties = {
135	  width: "100%",
136	  padding: "6px 10px",
137	  borderRadius: "var(--radius-sm)",
138	  border: "1px solid var(--color-border)",
139	  background: "var(--color-bg)",
140	  color: "var(--color-text)",
141	  fontSize: "0.875rem",
142	};
143

1	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
2	import * as api from "@/lib/api/client";
3	import type {
4	  AnalyticsInterval,
5	  ProbabilityEditPayload,
6	  EventTradePayload,
7	  CommentPayload,
8	  MarketCommentsResponse,
9	  Session,
10	  MarketListFilters,
11	} from "@/lib/api/types";
12	import { marketListQueryKey } from "@/lib/marketListFilters";
13	
14	export const queryKeys = {
15	  marketLists: () => ["markets", "list"] as const,
16	  markets: (filters: MarketListFilters = {}) =>
17	    [...queryKeys.marketLists(), marketListQueryKey(filters)] as const,
18	  market: (id: string) => ["markets", id] as const,
19	  marketEvents: (id: string) => ["markets", id, "events"] as const,
20	  marketComments: (id: string) => ["markets", id, "comments"] as const,
21	  engineStats: (id: string) => ["markets", id, "engine-stats"] as const,
22	  marketAnalytics: (id: string, interval?: AnalyticsInterval) =>
23	    [...queryKeys.market(id), "analytics", { interval: interval ?? null }] as const,
24	  account: (id: string) => ["accounts", id] as const,
25	  accountRisk: (id: string) => [...queryKeys.account(id), "risk"] as const,
26	  accountPnl: (id: string) => [...queryKeys.account(id), "pnl"] as const,
27	  health: () => ["health"] as const,
28	  serviceIndex: () => ["service-index"] as const,
29	};
30	
31	function createEmptyMarketCommentsResponse(marketId: string): MarketCommentsResponse {
32	  return {
33	    marketId,
34	    comments: [],
35	    pagination: {
36	      fromSeq: 0,
37	      limit: 0,
38	      returned: 0,
39	      nextFromSeq: null,
40	    },
41	    meta: {
42	      apiVersion: "unknown",
43	      timestamp: "1970-01-01T00:00:00.000Z",
44	    },
45	  };
46	}
47	
48	export function useMarkets(filters: MarketListFilters = {}) {
49	  return useQuery({
50	    queryKey: queryKeys.markets(filters),
51	    queryFn: () => api.listMarkets(filters),
52	    refetchInterval: 5000,
53	  });
54	}
55	
56	export function useMarket(marketId: string, opts?: { enabled?: boolean }) {
57	  return useQuery({
58	    queryKey: queryKeys.market(marketId),
59	    queryFn: () => api.getMarket(marketId),
60	    refetchInterval: 5000,
61	    enabled: opts?.enabled ?? true,
62	  });
63	}
64	
65	export function useMarketEvents(marketId: string) {
66	  return useQuery({
67	    queryKey: queryKeys.marketEvents(marketId),
68	    queryFn: () => api.getMarketEvents(marketId),
69	  });
70	}
71	
72	export function useMarketComments(marketId: string) {
73	  return useQuery({
74	    queryKey: queryKeys.marketComments(marketId),
75	    // Normalize missing mocks or empty responses into the same empty-thread UI state.
76	    queryFn: async () =>
77	      (await api.getMarketComments(marketId)) ?? createEmptyMarketCommentsResponse(marketId),
78	  });
79	}
80	
81	export function useEngineStats(marketId: string, opts?: { enabled?: boolean }) {
82	  return useQuery({
83	    queryKey: queryKeys.engineStats(marketId),
84	    queryFn: () => api.getEngineStats(marketId),
85	    enabled: opts?.enabled ?? true,
86	  });
87	}
88	
89	export function useMarketAnalytics(
90	  marketId: string,
91	  opts?: { enabled?: boolean; interval?: AnalyticsInterval },
92	) {
93	  return useQuery({
94	    queryKey: queryKeys.marketAnalytics(marketId, opts?.interval),
95	    queryFn: () => api.getMarketAnalytics(marketId, { interval: opts?.interval }),
96	    enabled: marketId.length > 0 && (opts?.enabled ?? true),
97	  });
98	}
99	
100	export const useAnalytics = useMarketAnalytics;
101	
102	export function useHealth() {
103	  return useQuery({
104	    queryKey: queryKeys.health(),
105	    queryFn: () => api.getHealth(),
106	    refetchInterval: 10000,
107	  });
108	}
109	
110	export function useServiceIndex() {
111	  return useQuery({
112	    queryKey: queryKeys.serviceIndex(),
113	    queryFn: () => api.getServiceIndex(),
114	    staleTime: 60000,
115	  });
116	}
117	
118	export function useAccountRisk(accountId: string) {
119	  return useQuery({
120	    queryKey: queryKeys.accountRisk(accountId),
121	    queryFn: () => api.getAccountRisk(accountId),
122	    enabled: accountId.length > 0,
123	  });
124	}
125	
126	export function useAccountPnl(accountId: string) {
127	  return useQuery({
128	    queryKey: queryKeys.accountPnl(accountId),
129	    queryFn: () => api.getAccountPnl(accountId),
130	    enabled: accountId.length > 0,
131	  });
132	}
133	
134	export function useCreateMarket() {
135	  const qc = useQueryClient();
136	  return useMutation({
137	    mutationFn: ({ payload, session }: { payload: api.CreateMarketPayload; session?: Session }) =>
138	      api.createMarket(payload, session),
139	    onSuccess: () => {
140	      void qc.invalidateQueries({ queryKey: queryKeys.marketLists() });
141	    },
142	  });
143	}
144	
145	export function useProbabilityEdit(marketId: string) {
146	  const qc = useQueryClient();
147	  return useMutation({
148	    mutationFn: ({ payload, session }: { payload: ProbabilityEditPayload; session: Session }) =>
149	      api.submitProbabilityEdit(marketId, payload, session),
150	    onSuccess: (_data, variables) => {
151	      void qc.invalidateQueries({ queryKey: queryKeys.market(marketId) });
152	      void qc.invalidateQueries({ queryKey: queryKeys.account(variables.payload.accountId) });
153	    },
154	  });
155	}
156	
157	export function useResolveMarket(marketId: string) {
158	  const qc = useQueryClient();
159	  return useMutation({
160	    mutationFn: ({ payload, session }: { payload: api.ResolveMarketPayload; session: Session }) =>
161	      api.resolveMarket(marketId, payload, session),
162	    onSuccess: (_data, variables) => {
163	      void qc.invalidateQueries({ queryKey: queryKeys.market(marketId) });
164	      void qc.invalidateQueries({ queryKey: queryKeys.account(variables.payload.accountId) });
165	      void qc.invalidateQueries({ queryKey: queryKeys.marketLists() });
166	    },
167	  });
168	}
169	
170	export function useEventTrade(marketId: string) {
171	  const qc = useQueryClient();
172	  return useMutation({
173	    mutationFn: ({ payload, session }: { payload: EventTradePayload; session: Session }) =>
174	      api.submitEventTrade(marketId, payload, session),
175	    onSuccess: (_data, variables) => {
176	      void qc.invalidateQueries({ queryKey: queryKeys.market(marketId) });
177	      void qc.invalidateQueries({ queryKey: queryKeys.account(variables.payload.accountId) });
178	    },
179	  });
180	}
181	
182	export function usePostMarketComment(marketId: string) {
183	  const qc = useQueryClient();
184	  return useMutation({
185	    mutationFn: ({ payload, session }: { payload: CommentPayload; session: Session }) =>
186	      api.submitMarketComment(marketId, payload, session),
187	    onSuccess: () => {
188	      void qc.invalidateQueries({ queryKey: queryKeys.marketComments(marketId) });
189	    },
190	  });
191	}
